VALUES
  ('optician-moex-00969', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '對一位近視1.00DS的患者，下列敘述何者正確？', '["未矯正時，遠點在眼後100cm處", "若需要全矯正，須配戴-1.00DS鏡片", "未矯正時，平行光進入眼睛，成像在視網膜後方", "若不考慮其他眼睛疾病，未矯正之視力值約為小數點制0.1左右"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00970', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '正常眼的視野範圍具有生理性限制，依照範圍由大至小排列，下列何者正確？', '["顳側＞上方＞下方或鼻側", "鼻側＞上方＞顳側或下方", "下方或鼻側＞顳側＞上方", "顳側＞下方＞鼻側或上方"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00971', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '使用筆燈進行眼球運動檢查，以了解眼外肌功能是否正常。下列敘述何者不適當？', '["配戴紅綠眼鏡，有助於判斷雙眼視線的偏差", "檢測時，受測者必須維持頭部不動，雙眼儘可能地跟隨目標（target）移動", "進行Ｈ型動眼檢查，當受測者向其左下方看時，右眼沒跟上，則右眼下直肌可能異常", "若以筆燈施測，必須確認受測者是否維持明顯的瞳孔光反射，確保施測範圍保持適當"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00972', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '關於調節幅度（amplitudeofaccommodation）檢查的敘述，下列何者正確？', '["負鏡片法（minuslensmethod）測得的結果，通常較推近法（push-upmethod）所測結果為低", "在標準近距離施測負鏡片法，在加到-4.00D後視標開始持續模糊，則該眼的調節幅度為4.00D", "檢查視標愈大時，調節幅度檢查結果愈小", "推近法測得的調節幅度，通常低於推遠法（pull-awaymethod）結果"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00973', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '關於交替遮蓋測試（alternatingcovertest），下列敘述何者正確？', '["移除遮蓋時，眼睛向外移動是外斜視", "外斜要用基底向外（baseout）稜鏡中和", "測量斜位或交替性斜視時，中和稜鏡棒放在那一眼都可以", "主要次要偏移量如果一致，屬於非共動性偏移"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00974', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '測量內聚的幅度（amplitudeofconvergence），假設受檢者的瞳孔間距PD是62mm，若近點內聚（nearpoint ofconvergence,NPC）距離為8cm（量到眼鏡頂尖距離），考慮眼鏡到眼球旋轉中心的距離為27mm，下列 何者為最接近真實的內聚幅度？（單位為：稜鏡屈光度，prismdiopter，Δ）', '["54", "58", "62", "66"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00975', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '一調節正常患者，近視-1.00DS屈光異常未矯正，調節近點（nearpointofaccommodation）位於眼前20cm， 則其調節幅度為下列何者？', '["3.00D", "4.00D", "5.00D", "6.00D"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00976', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '使用石原氏圖片（Ishiharapseudoisochromaticplates）檢查色覺，下列敘述何者錯誤？', '["做先天性色覺問題篩檢，可以兩眼一起檢查", "每一頁測驗圖只能看3秒左右，就需翻頁", "近測驗距離不是40cm，應拿遠一點至50～70cm距離", "光照明不需要很亮，可按照患者的需要增減亮度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00977', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '下列那些檢測項目可以全程在明亮的環境中進行？', '["遮蓋測試", "紅綠測試（duochrometest）", "布魯克納測試（Brücknertest）", "瞳孔檢查"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00978', 'optician', 'optician-moex-110-148c1cdf', 'sub-optician-04', NULL, 'single_choice', '下列何者可以檢查中心抑制性盲點（centralsuppressionscotoma）？', '["紅綠測試（duochrometest）檢查法", "馬竇氏鏡（Maddox-rodtest）檢查法", "魏氏四點（Worthfour-dottest）檢查法", "赫斯伯格（Hirschbergtest）檢查法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:31+00:00", "source_pdf_sha1": "fcc4d51ca0e3", "answer_pdf_sha1": "475ffd52dcb8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1107", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "驗光學概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
